import React, { useEffect, useMemo, useState } from "react";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";
import PageHeader from "../components/PageHeader";
import { createExpense, fetchCategories, fetchExpenses } from "../api/expenses";
import { useNavigate } from "react-router-dom";
import { formatCurrency } from "../utils/format";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const AddExpense = () => {
  const navigate = useNavigate();
  const [categories, setCategories] = useState([]);
  const [expenses, setExpenses] = useState([]);
  const [form, setForm] = useState({
    merchant: "",
    amount: "",
    expense_date: "",
    category: "",
    payment_method: "credit_card",
    description: "",
    receipt_file: null,
  });
  const [status, setStatus] = useState({ loading: false, error: "", success: "" });

  useEffect(() => {
    fetchCategories()
      .then(setCategories)
      .catch(() => setCategories([]));
  }, []);

  useEffect(() => {
    fetchExpenses()
      .then(setExpenses)
      .catch(() => setExpenses([]));
  }, []);

  const expenseSeries = useMemo(() => {
    const fallback = [
      { label: "Jan 12 - Aurora Travel", amount: 2430 },
      { label: "Jan 19 - City Bistro", amount: 214 },
      { label: "Jan 22 - Northwind Cloud", amount: 1180 },
      { label: "Feb 02 - Studio Nine", amount: 640 },
      { label: "Feb 08 - Orbit Supplies", amount: 310 },
    ];

    const rows = expenses.length
      ? expenses
          .map((expense) => {
            const rawDate = expense.expense_date || expense.date;
            const parsed = rawDate ? new Date(rawDate) : null;
            const labelDate = parsed && !Number.isNaN(parsed.getTime())
              ? parsed.toLocaleDateString("en-US", { month: "short", day: "2-digit" })
              : "Unknown";
            return {
              label: `${labelDate} - ${expense.merchant || expense.vendor || "Expense"}`,
              amount: Number(expense.amount || 0),
              sortKey: parsed ? parsed.getTime() : 0,
            };
          })
          .sort((a, b) => a.sortKey - b.sortKey)
      : fallback.map((item, index) => ({ ...item, sortKey: index }));

    return {
      labels: rows.map((row) => row.label),
      data: rows.map((row) => row.amount),
      total: rows.reduce((sum, row) => sum + row.amount, 0),
      count: rows.length,
    };
  }, [expenses]);

  const chartHeight = 360;

  const handleChange = (event) => {
    const { name, value } = event.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (event) => {
    setForm((prev) => ({ ...prev, receipt_file: event.target.files[0] }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setStatus({ loading: true, error: "", success: "" });
    try {
      const payload = new FormData();
      payload.append("merchant", form.merchant);
      payload.append("amount", form.amount);
      payload.append("expense_date", form.expense_date);
      payload.append("category", form.category);
      payload.append("payment_method", form.payment_method);
      payload.append("description", form.description);
      if (form.receipt_file) {
        payload.append("receipt_file", form.receipt_file);
      }
      await createExpense(payload);
      setStatus({ loading: false, error: "", success: "Expense submitted." });
      navigate("/expenses/history");
    } catch (error) {
      setStatus({ loading: false, error: "Unable to submit expense.", success: "" });
    }
  };
  return (
    <div className="page">
      <PageHeader
        title="Add expense"
        subtitle="Capture receipts and submit with the right policy context."
        actions={
          <button className="button button--ghost" type="button">
            Save draft
          </button>
        }
      />
      <div className="grid grid--two">
        <div className="card">
          <h3>Expense details</h3>
          <form className="form" onSubmit={handleSubmit}>
            <div className="field">
              <label htmlFor="vendor">Vendor</label>
              <input
                id="vendor"
                name="merchant"
                type="text"
                placeholder="Ex: Delta Airlines"
                value={form.merchant}
                onChange={handleChange}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="amount">Amount</label>
              <input
                id="amount"
                name="amount"
                type="number"
                step="0.01"
                placeholder="₹0.00"
                value={form.amount}
                onChange={handleChange}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="date">Expense date</label>
              <input
                id="date"
                name="expense_date"
                type="date"
                value={form.expense_date}
                onChange={handleChange}
                required
              />
            </div>
            <div className="field">
              <label htmlFor="category">Category</label>
              <select
                id="category"
                name="category"
                value={form.category}
                onChange={handleChange}
                required
              >
                <option value="">Select category</option>
                {categories.map((category) => (
                  <option key={category.id} value={category.id}>
                    {category.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="field">
              <label htmlFor="payment_method">Payment method</label>
              <select
                id="payment_method"
                name="payment_method"
                value={form.payment_method}
                onChange={handleChange}
              >
              
                <option value="credit_card">Credit card</option>
                <option value="debit_card">Debit card</option>
                <option value="cash">Cash</option>
                <option value="bank_transfer">Bank transfer</option>
                <option value="upi">UPI</option>
              </select>
            </div>
            <div className="field">
              <label htmlFor="notes">Notes</label>
              <textarea
                id="notes"
                name="description"
                placeholder="Add a short justification."
                value={form.description}
                onChange={handleChange}
                required
              />
            </div>
            {status.error ? <div className="alert">{status.error}</div> : null}
            <button className="button" type="submit">
              {status.loading ? "Submitting..." : "Submit expense"}
            </button>
          </form>
        </div>
        <div className="card">
          <h3>All expenses (bar chart)</h3>
          <div className="chart" style={{ height: chartHeight }}>
            <Bar
              data={{
                labels: expenseSeries.labels,
                datasets: [
                  {
                    label: "Expense amount",
                    data: expenseSeries.data,
                    backgroundColor: "rgba(219, 124, 45, 0.7)",
                    borderRadius: 8,
                  },
                ],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                  x: {
                    grid: { display: false },
                    ticks: { autoSkip: true, maxRotation: 60, minRotation: 45 },
                  },
                  y: { grid: { color: "rgba(0,0,0,0.05)" } },
                },
              }}
            />
          </div>
          <p className="stat-card__label">
            {expenseSeries.count} expenses, total {formatCurrency(expenseSeries.total)}
          </p>
        </div>
      </div>
      <div className="card">
        <h3>Receipt + policy preview</h3>
        <div className="field">
          <label htmlFor="receipt">Upload receipt</label>
          <input id="receipt" name="receipt_file" type="file" onChange={handleFileChange} />
        </div>
        <div className="list">
          <div className="list-item">
            <div>
              <strong>Policy match</strong>
              <div className="stat-card__label">Travel policy v3.2</div>
            </div>
            <span className="chip">Aligned</span>
          </div>
          <div className="list-item">
            <div>
              <strong>Manager review</strong>
              <div className="stat-card__label">Auto-route to J. Lee</div>
            </div>
            <span className="chip">2 hrs</span>
          </div>
          <div className="list-item">
            <div>
              <strong>Receipt check</strong>
              <div className="stat-card__label">OCR pending</div>
            </div>
            <span className="chip">Queued</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AddExpense;
